package main

import (
	"fmt"
	//"strings"
)





// mostra a lista com o elemento sword destacado
func ToStr(l *DList[int], sword *DNode[int]) string {

	str := "[ "


	for it := l.Front(); it != l.root; it = it.next{
		str+= fmt.Sprintf("%d", it.Value)

		if it == sword{
			str+=">"
		}

		str+= " "

	}

	return str + "]"
}

// move para frente na lista circular
func Next(l *DList[int], it *DNode[int]) *DNode[int] {

	if it.next == l.root{
		return l.root.next
	}
	return it.next
	//return nil
}

func main() {
	var qtd, chosen int
	fmt.Scan(&qtd, &chosen)
	//fmt.Println(qtd, chosen)
	l := NewDList[int]()
	for i := 1; i <= qtd; i++ {
		l.PushBack(i)
	}
	sword := l.Front()
	for range chosen - 1 {
		sword = Next(l, sword)
	}
	for range qtd - 1 {
		fmt.Println(ToStr(l, sword))
		l.Erase(Next(l, sword))
		sword = Next(l, sword)
	}
	fmt.Println(ToStr(l, sword))
}
